// MARK: - Token Storage

protocol TokenStorage {
    func saveTokens(access: String, refresh: String)
    func getAccessToken() -> String?
    func getRefreshToken() -> String?
    func clearTokens()
}

final class KeychainTokenStorage: TokenStorage {
    private let accessTokenKey = "com.example.app.accessToken"
    private let refreshTokenKey = "com.example.app.refreshToken"
    
    func saveTokens(access: String, refresh: String) {
        save(key: accessTokenKey, value: access)
        save(key: refreshTokenKey, value: refresh)
    }
    
    func getAccessToken() -> String? {
        return load(key: accessTokenKey)
    }
    
    func getRefreshToken() -> String? {
        return load(key: refreshTokenKey)
    }
    
    func clearTokens() {
        delete(key: accessTokenKey)
        delete(key: refreshTokenKey)
    }
    
    // MARK: - Keychain Helpers
    
    private func save(key: String, value: String) {
        guard let data = value.data(using: .utf8) else { return }
        
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecAttrAccessible as String: kSecAttrAccessibleAfterFirstUnlockThisDeviceOnly
        ]
        
        SecItemDelete(query as CFDictionary)
        
        var addQuery = query
        addQuery[kSecValueData as String] = data
        
        SecItemAdd(addQuery as CFDictionary, nil)
    }
    
    private func load(key: String) -> String? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        guard status == errSecSuccess, let data = result as? Data else {
            return nil
        }
        
        return String(data: data, encoding: .utf8)
    }
    
    private func delete(key: String) {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key
        ]
        SecItemDelete(query as CFDictionary)
    }
}

// MARK: - SSL Pinning Delegate

final class SSLPinningDelegate: NSObject, URLSessionDelegate {
    private let environment: AppEnvironment
    
    init(environment: AppEnvironment) {
        self.environment = environment
        super.init()
    }
    
    func urlSession(
        _ session: URLSession,
        didReceive challenge: URLAuthenticationChallenge,
        completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void
    ) {
        guard challenge.protectionSpace.authenticationMethod == NSURLAuthenticationMethodServerTrust else {
            completionHandler(.performDefaultHandling, nil)
            return
        }
        
        guard let serverTrust = challenge.protectionSpace.serverTrust else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }
        
        let host = challenge.protectionSpace.host
        
        // For non-pinned hosts or non-production environments, use default TLS validation
        guard environment.requiresCertificatePinning,
              environment.pinnedHosts.contains(host) else {
            // Still perform standard TLS validation
            let credential = URLCredential(trust: serverTrust)
            completionHandler(.performDefaultHandling, credential)
            return
        }
        
        // Perform standard TLS evaluation first
        let policy = SecPolicyCreateSSL(true, host as CFString)
        SecTrustSetPolicies(serverTrust, policy)
        
        var error: CFError?
        guard SecTrustEvaluateWithError(serverTrust, &error) else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }
        
        // Attempt certificate pinning first, then fall back to public key pinning
        if verifyCertificatePinning(serverTrust: serverTrust) ||
            verifyPublicKeyPinning(serverTrust: serverTrust) {
            let credential = URLCredential(trust: serverTrust)
            completionHandler(.useCredential, credential)
        } else {
            completionHandler(.cancelAuthenticationChallenge, nil)
        }
    }
    
    // MARK: - Certificate Pinning
    
    private func verifyCertificatePinning(serverTrust: SecTrust) -> Bool {
        let certificateNames = environment.pinnedCertificateNames
        guard !certificateNames.isEmpty else { return false }
        
        // Load bundled certificates
        let pinnedCertificates: [SecCertificate] = certificateNames.compactMap { name in
            guard let certURL = Bundle.main.url(forResource: name, withExtension: "cer"),
                  let certData = try? Data(contentsOf: certURL),
                  let certificate = SecCertificateCreateWithData(nil, certData as CFData) else {
                return nil
            }
            return certificate
        }
        
        guard !pinnedCertificates.isEmpty else { return false }
        
        // Get server certificate chain
        let serverCertificateCount = SecTrustGetCertificateCount(serverTrust)
        
        for index in 0..<serverCertificateCount {
            guard let serverCertificate = SecTrustGetCertificateAtIndex(serverTrust, index) else {
                continue
            }
            
            let serverCertData = SecCertificateCopyData(serverCertificate) as Data
            
            for pinnedCert in pinnedCertificates {
                let pinnedCertData = SecCertificateCopyData(pinnedCert) as Data
                if serverCertData == pinnedCertData {
                    return true
                }
            }
        }
        
        return false
    }
    
    // MARK: - Public Key Pinning
    
    private func verifyPublicKeyPinning(serverTrust: SecTrust) -> Bool {
        let pinnedHashes = environment.pinnedPublicKeyHashes
        guard !pinnedHashes.isEmpty else { return false }
        
        let serverCertificateCount = SecTrustGetCertificateCount(serverTrust)
        
        for index in 0..<serverCertificateCount {
            guard let certificate = SecTrustGetCertificateAtIndex(serverTrust, index) else {
                continue
            }
            
            if let publicKeyHash = publicKeyHashForCertificate(certificate) {
                if pinnedHashes.contains(publicKeyHash) {
                    return true
                }
            }
        }
        
        return false
    }
    
    private func publicKeyHashForCertificate(_ certificate: SecCertificate) -> String? {
        guard let publicKey = SecCertificateCopyKey(certificate) else {
            return nil
        }
        
        var error: Unmanaged<CFError>?
        guard let publicKeyData = SecKeyCopyExternalRepresentation(publicKey, &error) as Data? else {
            return nil
        }
        
        // Add the appropriate ASN.1 header for RSA 2048-bit keys
        // This creates the Subject Public Key Info (SPKI) format
        let rsa2048SPKIHeader: [UInt8] = [
            0x30, 0x82, 0x01, 0x22, 0x30, 0x0d, 0x06, 0x09,
            0x2a, 0x86, 0x48, 0x86, 0xf7, 0x0d, 0x01, 0x01,
            0x01, 0x05, 0x00, 0x03, 0x82, 0x01, 0x0f, 0x00
        ]
        
        // For EC keys (P-256), use a different header
        let ecdsaSecp256r1SPKIHeader: [UInt8] = [
            0x30, 0x59, 0x30, 0x13, 0x06, 0x07, 0x2a, 0x86,
            0x48, 0xce, 0x3d, 0x02, 0x01, 0x06, 0x08, 0x2a,
            0x86, 0x48, 0xce, 0x3d, 0x03, 0x01, 0x07, 0x03,
            0x42, 0x00
        ]
        
        // Determine key type and select appropriate header
        let header: [UInt8]
        if let keyAttributes = SecKeyCopyAttributes(publicKey) as? [String: Any],
           let keyType = keyAttributes[kSecAttrKeyType as String] as? String {
            if keyType == (kSecAttrKeyTypeRSA as String) {
                header = rsa2048SPKIHeader
            } else if keyType == (kSecAttrKeyTypeECSECPrimeRandom as String) {
                header = ecdsaSecp256r1SPKIHeader
            } else {
                header = rsa2048SPKIHeader // Default to RSA
            }
        } else {
            header = rsa2048SPKIHeader
        }
        
        var spkiData = Data(header)
        spkiData.append(publicKeyData)
        
        let hash = SHA256.hash(data: spkiData)
        return Data(hash).base64EncodedString()
    }
}

// MARK: - Network Client Protocol

protocol NetworkClientProtocol {
    func request<T: Decodable>(
        endpoint: APIEndpoint,
        body: Encodable?,
        config: RequestConfiguration?,
        responseType: T.Type
    ) async throws -> T
    
    func request<T: Decodable>(
        method: HTTPMethod,
        path: String,
        body: Encodable?,
        config: RequestConfiguration?,
        responseType: T.Type
    ) async throws -> T
}

// MARK: - Network Client

final class NetworkClient: NetworkClientProtocol {
    static let shared = NetworkClient()
    
    private let environment: AppEnvironment
    private let tokenStorage: TokenStorage
    private let session: URLSession
    private let sslPinningDelegate: SSLPinningDelegate
    private let jsonEncoder: JSONEncoder
    private let jsonDecoder: JSONDecoder
    
    private var isRefreshingToken = false
    private let tokenRefreshLock = NSLock()
    
    init(
        environment: AppEnvironment = .production,
        tokenStorage: TokenStorage = KeychainTokenStorage()
    ) {
        self.environment = environment
        self.tokenStorage = tokenStorage
        self.sslPinningDelegate = SSLPinningDelegate(environment: environment)
        
        let configuration = URLSessionConfiguration.default
        configuration.timeoutIntervalForRequest = 30
        configuration.timeoutIntervalForResource = 60
        configuration.waitsForConnectivity = true
        configuration.tlsMinimumSupportedProtocolVersion = .TLSv12
        
        self.session = URLSession(
            configuration: configuration,
            delegate: sslPinningDelegate,
            delegateQueue: nil
        )
        
        self.jsonEncoder = JSONEncoder()
        self.jsonEncoder.dateEncodingStrategy = .iso8601
        
        self.jsonDecoder = JSONDecoder()
        self.jsonDecoder.dateDecodingStrategy = .iso8601
    }
    
    // MARK: - Public API
    
    func request<T: Decodable>(
        endpoint: APIEndpoint,
        body: Encodable? = nil,
        config: RequestConfiguration? = nil,
        responseType: T.Type
    ) async throws -> T {
        return try await request(
            method: endpoint.method,
            path: endpoint.path,
            body: body,
            config: config,
            responseType: responseType,
            requiresAuth: endpoint.requiresAuth
        )
    }
    
    func request<T: Decodable>(
        method: HTTPMethod,
        path: String,
        body: Encodable? = nil,
        config: RequestConfiguration? = nil,
        responseType: T.Type
    ) async throws -> T {
        return try await request(
            method: method,
            path: path,
            body: body,
            config: config,
            responseType: responseType,
            requiresAuth: true
        )
    }
    
    // MARK: - Private Implementation
    
    private func request<T: Decodable>(
        method: HTTPMethod,
        path: String,
        body: Encodable?,
        config: RequestConfiguration?,
        responseType: T.Type,
        requiresAuth: Bool,
        isRetry: Bool = false
    ) async throws -> T {
        let urlRequest = try buildRequest(
            method: method,
            path: path,
            body: body,
            config: config,
            requiresAuth: requiresAuth
        )
        
        let (data, response) = try await performRequest(urlRequest)
        
        guard let httpResponse = response as? HTTPURLResponse else {
            throw NetworkError.unknown(NSError(domain: "NetworkClient", code: -1, userInfo: [NSLocalizedDescriptionKey: "Invalid response type"]))
        }
        
        // Handle 401 with token refresh
        if httpResponse.statusCode == 401 && requiresAuth && !isRetry {
            try await refreshTokenIfNeeded()
            return try await request(
                method: method,
                path: path,
                body: body,
                config: config,
                responseType: responseType,
                requiresAuth: requiresAuth,
                isRetry: true
            )
        }
        
        try validateResponse(httpResponse, data: data)
        
        do {
            let decoded = try jsonDecoder.decode(T.self, from: data)
            return decoded
        } catch {
            throw NetworkError.decodingError(error)
        }
    }
    
    private func buildRequest(
        method: HTTPMethod,
        path: String,
        body: Encodable?,
        config: RequestConfiguration?,
        requiresAuth: Bool
    ) throws -> URLRequest {
        var urlString = environment.baseURL + path
        
        // Add query parameters
        if let queryParams = config?.queryParameters, !queryParams.isEmpty {
            var components = URLComponents(string: urlString)
            components?.queryItems = queryParams.map { URLQueryItem(name: $0.key, value: $0.value) }
            if let updatedURL = components?.string {
                urlString = updatedURL
            }
        }
        
        guard let url = URL(string: urlString) else {
            throw NetworkError.invalidURL
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = method.rawValue
        request.timeoutInterval = config?.timeoutInterval ?? 30
        request.cachePolicy = config?.cachePolicy ?? .useProtocolCachePolicy
        
        // Default headers
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        request.setValue("application/json", forHTTPHeaderField: "Accept")
        request.setValue("ExampleApp/1.0", forHTTPHeaderField: "User-Agent")
        
        // Auth header
        if requiresAuth, let token = tokenStorage.getAccessToken() {
            request.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        }
        
        // Custom headers
        if let customHeaders = config?.headers {
            for (key, value) in customHeaders {
                request.setValue(value, forHTTPHeaderField: key)
            }
        }
        
        // Body
        if let body = body {
            do {
                request.httpBody = try jsonEncoder.encode(body)
            } catch {
                throw NetworkError.encodingError(error)
            }
        }
        
        return request
    }
    
    private func performRequest(_ request: URLRequest) async throws -> (Data, URLResponse) {
        do {
            return try await session.data(for: request)
        } catch let urlError as URLError {
            switch urlError.code {
            case .notConnectedToInternet, .networkConnectionLost:
                throw NetworkError.networkUnavailable
            case .serverCertificateUntrusted,
                 .serverCertificateHasBadDate,
                 .serverCertificateNotYetValid,
                 .serverCertificateHasUnknownRoot:
                throw NetworkError.certificateValidationFailed
            case .cancelled:
                // Cancelled challenges from pinning failures surface as cancelled errors
                if environment.requiresCertificatePinning {
                    throw NetworkError.sslPinningFailed
                }
                throw NetworkError.unknown(urlError)
            default:
                throw NetworkError.unknown(urlError)
            }
        } catch {
            throw NetworkError.unknown(error)
        }
    }
    
    private func validateResponse(_ response: HTTPURLResponse, data: Data) throws {
        switch response.statusCode {
        case 200...299:
            return
        case 401:
            throw NetworkError.unauthorized
        case 400...499:
            if let errorResponse = try? jsonDecoder.decode(APIErrorResponse.self, from: data) {
                throw NetworkError.serverError(errorResponse.message)
            }
            throw NetworkError.httpError(statusCode: response.statusCode, data: data)
        case 500...599:
            if let errorResponse = try? jsonDecoder.decode(APIErrorResponse.self, from: data) {
                throw NetworkError.serverError(errorResponse.message)
            }
            throw NetworkError.httpError(statusCode: response.statusCode, data: data)
        default:
            throw NetworkError.httpError(statusCode: response.statusCode, data: data)
        }
    }
    
    // MARK: - Token Refresh
    
    private func refreshTokenIfNeeded() async throws {
        tokenRefreshLock.lock()
        
        guard !isRefreshingToken else {
            tokenRefreshLock.unlock()
            // Wait briefly for the other refresh to complete
            try await Task.sleep(nanoseconds: 500_000_000)
            return
        }
        
        isRefreshingToken = true
        tokenRefreshLock.unlock()
        
        defer {
            tokenRefreshLock.lock()
            isRefreshingToken = false
            tokenRefreshLock.unlock()
        }
        
        guard let refreshToken = tokenStorage.getRefreshToken() else {
            tokenStorage.clearTokens()
            throw NetworkError.unauthorized
        }
        
        struct RefreshRequest: Codable {
            let refreshToken: String
            enum CodingKeys: String, CodingKey {
                case refreshToken = "refresh_token"
            }
        }
        
        let refreshRequest = RefreshRequest(refreshToken: refreshToken)
        
        let urlRequest = try buildRequest(
            method: .post,
            path: APIEndpoint.refreshToken.path,
            body: refreshRequest,
            config: nil,
            requiresAuth: false
        )
        
        let (data, response) = try await performRequest(urlRequest)
        
        guard let httpResponse = response as? HTTPURLResponse,
              (200...299).contains(httpResponse.statusCode) else {
            tokenStorage.clearTokens()
            throw NetworkError.unauthorized
        }
        
        do {
            let authResponse = try jsonDecoder.decode(AuthResponse.self, from: data)
            tokenStorage.saveTokens(
                access: authResponse.accessToken,
                refresh: authResponse.refreshToken
            )
        } catch {
            tokenStorage.clearTokens()
            throw NetworkError.unauthorized
        }
    }
}

// MARK: - API Service

final class APIService {
    private let client: NetworkClientProtocol
    private let tokenStorage: TokenStorage
    
    init(
        client: NetworkClientProtocol = NetworkClient.shared,
        tokenStorage: TokenStorage = KeychainTokenStorage()
    ) {
        self.client = client
        self.tokenStorage = tokenStorage
    }
    
    // MARK: - Authentication
    
    func login(email: String, password: String) async throws -> AuthResponse {
        let body = LoginRequest(email: email, password: password)
        let response: AuthResponse = try await client.request(
            endpoint: .login,
            body: body,
            responseType: AuthResponse.self
        )
        tokenStorage.saveTokens(
            access: response.accessToken,
            refresh: response.refreshToken
        )
        return response
    }
    
    func register(email: String, password: String, firstName: String, lastName: String) async throws -> AuthResponse {
        let body = RegisterRequest(
            email: email,
            password: password,
            firstName: firstName,
            lastName: lastName
        )
        let response: AuthResponse = try await client.request(
            endpoint: .register,
            body: body,
            responseType: AuthResponse.self
        )
        tokenStorage.saveTokens(
            access: response.accessToken,
            refresh: response.refreshToken
        )
        return response
    }
    
    func logout() {
        tokenStorage.clearTokens()
    }
    
    // MARK: - User Data
    
    func fetchCurrentUser() async throws -> User {
        return try await client.request(
            endpoint: .userProfile,
            body: nil,
            responseType: User.self
        )
    }
    
    func fetchUser(id: String) async throws -> User {
        return try await client.request(
            endpoint: .user(id: id),
            body: nil,
            responseType: User.self
        )
    }
    
    func fetchUsers(page: Int = 1, perPage: Int = 20) async throws -> PaginatedResponse<User> {
        let config = RequestConfiguration(
            queryParameters: [
                "page": "\(page)",
                "per_page": "\(perPage)"
            ]
        )
        return try await client.request(
            endpoint: .users,
            body: nil,
            config: config,
            responseType: PaginatedResponse<User>.self
        )
    }
    
    func updateProfile(firstName: String? = nil, lastName: String? = nil, avatarURL: String? = nil) async throws -> User {
        let body = UpdateProfileRequest(
            firstName: firstName,
            lastName: lastName,
            avatarURL: avatarURL
        )
        return try await client.request(
            endpoint: .updateProfile,
            body: body,
            responseType: User.self
        )
    }
}

